// Assuming you are using express and cookie-parser
const express = require('express');
const cookieParser = require('cookie-parser');
const app = express();
app.use(cookieParser());

app.post('/login', function(req, res){
  var username = req.body.username;
  var password = req.body.password; // You should be hashing this password

  // Your function to authenticate users
  authenticate(username, password, function(err, user){
    if(user){
      if(req.body.remember) {
        res.cookie('rememberUser', { username: user.username, hashedPassword: user.hashedPassword }, { maxAge: 30 * 24 * 60 * 60 * 1000 }); // Cookies set for 30 days
      }
      res.send('Logged In!');
    } else {
      res.send('Auth Failed')
    }
  });
});

app.get('/', function(req, res){
  var user = req.cookies.rememberUser;
  if(user){
    authenticate(user.username, user.hashedPassword, function(err, user){
      if(user){
        res.send('Logged In as: ' + user.username);
      } else {
        res.send('Auth Failed')
      }
    });
  } else {
    // Render your regular login page
    res.sendFile('/login.html');
  }
});